def minWindow(s, t):
    if not t or not s:
        return ""

    count_t = {}
    for c in t:
        count_t[c] = count_t.get(c, 0) + 1

    need = len(count_t)
    have = 0
    window = {}
    res = ""
    res_len = float('inf')
    l = 0

    for r in range(len(s)):
        c = s[r]
        window[c] = window.get(c, 0) + 1

        if c in count_t and window[c] == count_t[c]:
            have += 1

        while have == need:
            if (r - l + 1) < res_len:
                res_len = r - l + 1
                res = s[l:r + 1]

            window[s[l]] -= 1
            if s[l] in count_t and window[s[l]] < count_t[s[l]]:
                have -= 1
            l += 1

    return res

